function update_event_rule(arn; aws_config::AbstractAWSConfig=current_aws_config())
    return notifications(
        "PUT", "/event-rules/$(arn)"; aws_config, feature_set=SERVICE_FEATURE_SET
    )
end

function update_event_rule(
    arn, params::AbstractDict{String}; aws_config::AbstractAWSConfig=current_aws_config()
)
    return notifications(
        "PUT", "/event-rules/$(arn)", params; aws_config, feature_set=SERVICE_FEATURE_SET
    )
end

"""
    update_notification_configuration(arn)
    update_notification_configuration(arn, params::Dict{String,<:Any})

Updates a `NotificationConfiguration`.

# Arguments

- `arn`: The Amazon Resource Name (ARN) used to update the `NotificationConfiguration`.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"aggregationDuration"`: The aggregation preference of the `NotificationConfiguration`.

  - Values:
    - `LONG`
      - Aggregate notifications for long periods of time (12 hours).
    - `SHORT`
      - Aggregate notifications for short periods of time (5 minutes).
    - `NONE`
      - Don't aggregate notifications.

- `"description"`: The description of the `NotificationConfiguration`.

- `"name"`: The name of the `NotificationConfiguration`.
"""
function update_notification_configuration end

function update_notification_configuration(
    arn; aws_config::AbstractAWSConfig=current_aws_config()
)
    return notifications(
        "PUT",
        "/notification-configurations/$(arn)";
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_notification_configuration(
    arn, params::AbstractDict{String}; aws_config::AbstractAWSConfig=current_aws_config()
)
    return notifications(
        "PUT",
        "/notification-configurations/$(arn)",
        params;
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
